import { execFileSync } from "node:child_process";
import { existsSync, mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { dirname, resolve } from "node:path";

const GENERATED_NOTICE =
  "Generated by pnpm --filter @aether-agent/sdk generate:config-types. Do not edit manually.";
const TS_HEADER = `// @generated ${GENERATED_NOTICE}\n// Source: packages/aether-project/src/config.rs via aether-config-schema.\n\n`;

const root = resolve(import.meta.dirname, "../../..");
const generatedDir = resolve(import.meta.dirname, "../src/generated");
const schemaPath = resolve(generatedDir, "aether-config.schema.json");
const typesPath = resolve(generatedDir, "aether-config.ts");
const check = process.argv.includes("--check");

const rustSchema = execFileSync(
  "cargo",
  ["run", "-q", "-p", "aether-project", "--bin", "aether-config-schema"],
  { cwd: root, encoding: "utf8" },
);

const schema = withGeneratedComment(JSON.parse(rustSchema));
const outputs = [
  {
    path: schemaPath,
    content: formatWithPrettier(`${JSON.stringify(schema, null, 2)}\n`, "json"),
  },
  {
    path: typesPath,
    content: formatWithPrettier(generateTypes(schema), "typescript"),
  },
];

if (check) {
  const drifted = outputs.filter(
    ({ path, content }) =>
      !existsSync(path) || readFileSync(path, "utf8") !== content,
  );
  if (drifted.length > 0) {
    console.error(
      `Generated config artifacts are out of date:\n${drifted
        .map(({ path }) => `  - ${path}`)
        .join(
          "\n",
        )}\nRun pnpm --filter @aether-agent/sdk generate:config-types.`,
    );
    process.exit(1);
  }
  console.log("generated config artifacts are up to date");
} else {
  mkdirSync(generatedDir, { recursive: true });
  for (const { path, content } of outputs) writeFileSync(path, content);
  console.log(`wrote ${dirname(schemaPath)}`);
}

function withGeneratedComment(schema) {
  const { $schema, $comment: _oldComment, ...rest } = schema;
  return { $schema, $comment: GENERATED_NOTICE, ...rest };
}

function formatWithPrettier(content, parser) {
  return execFileSync("pnpm", ["exec", "prettier", "--parser", parser], {
    cwd: root,
    input: content,
    encoding: "utf8",
  });
}

function generateTypes(schema) {
  const chunks = [
    TS_HEADER.trimEnd(),
    "",
    renderNamed(schema.title ?? "AetherConfig", schema),
  ];
  for (const [name, definition] of Object.entries(schema.$defs ?? {})) {
    chunks.push("", renderNamed(name, definition));
  }
  return `${chunks.join("\n")}\n`;
}

function renderNamed(name, schema) {
  if (isPlainObject(schema))
    return `export interface ${name} ${renderObject(schema, 0)}`;

  const rendered = renderType(schema, 0);
  return `export type ${name} =${rendered.startsWith("\n") ? rendered : ` ${rendered}`};`;
}

function renderType(schema, indent) {
  if (!schema || typeof schema !== "object") return "unknown";
  if (schema.$ref) return refName(schema.$ref);
  if (Object.hasOwn(schema, "const")) return literal(schema.const);
  if (Array.isArray(schema.enum))
    return renderUnion(schema.enum.map(literal), indent);

  if (hasObjectShape(schema) && Array.isArray(schema.anyOf)) {
    const { anyOf: _anyOf, ...baseSchema } = schema;
    const variants = schema.anyOf.map((entry) => renderType(entry, indent + 2));
    return `${renderObject(baseSchema, indent)} & (${renderUnion(variants, indent + 1)}\n${"  ".repeat(indent)})`;
  }

  if (Array.isArray(schema.anyOf))
    return renderUnion(
      schema.anyOf.map((entry) => renderType(entry, indent + 2)),
      indent + 1,
    );
  if (Array.isArray(schema.oneOf))
    return renderUnion(
      schema.oneOf.map((entry) => renderType(entry, indent + 2)),
      indent + 1,
    );

  if (Array.isArray(schema.type)) {
    return renderUnion(
      schema.type.map((type) => renderType({ ...schema, type }, indent)),
      indent,
    );
  }

  switch (schema.type) {
    case "string":
      return "string";
    case "integer":
    case "number":
      return "number";
    case "boolean":
      return "boolean";
    case "null":
      return "null";
    case "array": {
      const itemType = renderType(schema.items ?? {}, indent);
      return `${needsParens(itemType) ? `(${itemType})` : itemType}[]`;
    }
    case "object":
      return renderObject(schema, indent);
    default:
      if (hasObjectShape(schema)) return renderObject(schema, indent);
      return "unknown";
  }
}

function renderObject(schema, indent) {
  const properties = schema.properties ?? {};
  const entries = orderedProperties(properties);
  const required = new Set(schema.required ?? []);

  if (entries.length === 0) {
    if (
      schema.additionalProperties &&
      typeof schema.additionalProperties === "object"
    ) {
      return `Record<string, ${renderType(schema.additionalProperties, indent)}>`;
    }
    return "Record<string, unknown>";
  }

  const pad = "  ".repeat(indent);
  const innerPad = "  ".repeat(indent + 1);
  const lines = entries.map(([key, value]) => {
    const optional = required.has(key) ? "" : "?";
    return `${innerPad}${propertyName(key)}${optional}: ${renderType(value, indent + 1)};`;
  });
  return `{\n${lines.join("\n")}\n${pad}}`;
}

function orderedProperties(properties) {
  return Object.entries(properties).sort(
    ([left, leftSchema], [right, rightSchema]) => {
      const leftDiscriminator =
        left === "type" && Object.hasOwn(leftSchema, "const");
      const rightDiscriminator =
        right === "type" && Object.hasOwn(rightSchema, "const");
      if (leftDiscriminator === rightDiscriminator) return 0;
      return leftDiscriminator ? -1 : 1;
    },
  );
}

function refName(ref) {
  const prefix = "#/$defs/";
  if (!ref.startsWith(prefix))
    throw new Error(`Unsupported JSON Schema ref: ${ref}`);
  return ref.slice(prefix.length);
}

function renderUnion(types, indent = 0) {
  const unique = [...new Set(types)];
  if (!unique.some((type) => type.includes("\n") || type.startsWith("{"))) {
    return unique.join(" | ");
  }

  const pad = "  ".repeat(indent);
  return `\n${unique.map((type) => `${pad}| ${type}`).join("\n")}`;
}

function literal(value) {
  return value === null ? "null" : JSON.stringify(value);
}

function propertyName(name) {
  return /^[A-Za-z_$][\w$]*$/.test(name) ? name : JSON.stringify(name);
}

function needsParens(type) {
  return type.includes(" | ") || type.includes(" & ");
}

function isPlainObject(schema) {
  return (
    hasObjectShape(schema) &&
    !schema.anyOf &&
    !schema.oneOf &&
    !schema.allOf &&
    !schema.$ref &&
    !schema.enum
  );
}

function hasObjectShape(schema) {
  return (
    schema.type === "object" ||
    Boolean(schema.properties) ||
    Boolean(schema.additionalProperties)
  );
}
